func TestEnumExportFormat1(t *testing.T) {
	t.Run("NewFromString_csv", func(t *testing.T) {
		t.Parallel()
		val, err := NewExportFormat1FromString("csv")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, ExportFormat1("csv"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_xlsx", func(t *testing.T) {
		t.Parallel()
		val, err := NewExportFormat1FromString("xlsx")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, ExportFormat1("xlsx"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewExportFormat1FromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewExportFormat1FromString("csv")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}
